jQuery(function(e){e(".modal-video-button").modalVideo()}),document.addEventListener("DOMContentLoaded",()=>{const e=document.querySelector(".hero-banner__video");if(!e)return;const t=e.querySelector("video"),o=e.querySelector(".audio-toggle");t&&o&&o.addEventListener("click",function(){t.muted=!t.muted,o.classList.toggle("is-muted",t.muted),o.setAttribute("aria-pressed",t.muted?"false":"true")})});